import React, {Component} from 'react';
import './App.css';
import ListItems from './listItems'
// import Person from './Person/Person' ;
import X from './1.gif'
import './img.css'
import NavBar from './nav'
import {BrowserRouter as Router, Route, Switch} from 'react-router-dom'
import '../node_modules/font-awesome/css/font-awesome.min.css';
import './dragon.css' 
import Person from './comp'
import styled from 'styled-components';
import {FiShoppingCart} from 'react-icons/fi'
import {GiCongress} from 'react-icons/gi'
import {FaDragon} from 'react-icons/fa'
import {FaPaypal} from 'react-icons/fa'
import {FaCcVisa} from 'react-icons/fa'
import {FaCcMastercard} from 'react-icons/fa'
import {FaBtc} from 'react-icons/fa'
import {FaEthereum} from 'react-icons/fa'
import {FaGift} from 'react-icons/fa'

import {
    FacebookIcon,
    TwitterIcon,
    WhatsappIcon,

  } from "react-share";

class App extends Component {

    constructor(props) {
        super(props)
        this.state = {
            showLogin: false,
        }
    }


    clickHandler = () => {
        const doesShow = this.state.showLogin;
        this.setState({ showLogin: !doesShow })

    }


    render() {

        const style = {
            margintop: '100px',
            marginleft: '300px'
        }

        let Y = null;

        if(this.state.showLogin===true) {
            Y = (
                //  <div className="login" > </div>
                <Person name="Ali" />

            )
        }


        return (   

            <div>
                <Router>

                <NavBar/>

                <div className="gift" >
                <FaGift size={65} style={{color:'Purple' , marginBottom:'100px' ,paddingTop: '10px',paddingBlock: '10px', borderColor: 'red' , borderStyle: 'solid'}} /> <h1>Deals</h1>
                </div>


                </Router>


            <div className="App3" >
                <br/>
            <FaPaypal className="icons" style={{marginLeft:"50px" , color:'purple' }} size={42} round={true} />
            <FaCcVisa className="icons" style={{marginLeft:"50px", color :'white'  }}  size={42} round={true} />
            <FaCcMastercard className="icons"  style={{marginLeft:"50px", color :'red' }} size={42} round={true} />
            <FaBtc className="icons" style={{marginLeft:"50px", color:"orange" }} size={42} round={true}  />
            <FaEthereum className="icons" style={{marginLeft:"50px", color:"purple" }} size={42} round={true} />
            </div>

             <div  className = "App">  

          <header>


              <form id = "ToDo-Form"  >

                  {/* <img style={{height:'200px' ,marginRight:'60px' }  } src= {X} alt="Hello" /> */}
                  <img className="Img" src= {X} alt="Hello" />
                  <br/>
                  <br/>

                  {/* <input type="text" placeholder="Enter text" 
                //   value = {this.state.currentItem.text} 
                //   onChange={this.handleInput} 
                /> */}
                  <button >Next</button>
                  <br/>
                  <FiShoppingCart className="cart" size={50}/>



              </form>

          </header>

          <div className="App2" >
                  <TwitterIcon className="icons" size={42} round={true} /> 
                  <br/>
                  <FacebookIcon className="icons" size={42} round={true} />
                  <br/>
                  <WhatsappIcon className="icons" size={42} round={true} />
                  <br/>
                  <br/>
                  <br/>
                  <br/>

                  <div className="B" >
                  <FaDragon className="dragon" size={60} onClick={this.clickHandler} /> <h className="C">AbdulSamad</h>
                  </div>



          </div>


          </div> 
          </div>
        );
    }
}

export default App
